int diffMaxMin(int num) {
    int maxRemap = 1, minRemap = 9;
    String numStr = Integer.toString(num);
    for (int i = 0; i < numStr.length(); i++) {
        int digit = numStr.charAt(i) - '0';
        maxRemap = Math.max(maxRemap, 9 - digit);
        if (digit != 0) {
            minRemap = Math.min(minRemap, digit);
        }
    }
    int maxValue = num + maxRemap * (numStr.length() - numStr.replaceAll(Character.toString((char)('9' - maxRemap)), "").length());
    int minValue = num - minRemap * (numStr.length() - numStr.replaceAll(Character.toString((char)(minRemap + '0')), "").length());
    return maxValue - minValue;
}
```

